INSERT INTO itens (
  nome,
  descricao,
  categoria_id,
  unidade_medida_id,
  eh_movel,
  eh_consumivel,
  permite_emprestimo,
  dias_emprestimo_padrao,
  ativo
)
SELECT
  ni.nome,
  ni.descricao_origem,
  (SELECT id FROM categorias      WHERE nome   = ni.categoria_nome LIMIT 1),
  (SELECT id FROM unidades_medida WHERE codigo = ni.unidade_codigo LIMIT 1),
  ni.eh_movel,
  ni.eh_consumivel,
  ni.permite_emprestimo,
  ni.dias_emprestimo,
  true
FROM novos_itens ni
WHERE NOT EXISTS (
  SELECT 1 FROM itens i WHERE i.nome = ni.nome
);

COMMIT;

